def is_sequential_string(secret: str) -> bool:
    sequences = (string.ascii_uppercase + string.ascii_uppercase + string.digits + '+/', string.digits + string.ascii_uppercase + string.ascii_uppercase + '+/', (string.digits + string.ascii_uppercase) * 2, string.digits * 2, string.hexdigits.upper() + string.hexdigits.upper(), string.ascii_uppercase + '=/')
