import binascii
from six import int2byte
def encode_length(l):
    assert l >= 0
    if l < 128:
        return int2byte(l)
    s = ('%x' % l).encode()
    if len(s) % 2:
        s = b'0' + s
    s = binascii.unhexlify(s)
    llen = len(s)
    return int2byte(128 | llen) + s

