def jacobi(a, n):
    """Jacobi symbol"""
    if not n >= 3:
        raise JacobiError('n must be larger than 2')
    if not n % 2 == 1:
        raise JacobiError('n must be odd')
    a = a % n
    if a == 0:
        return 0
    if a == 1:
        return 1
    a1, e = a, 0
    while a1 % 2 == 0:
        a1, e = a1 // 2, e + 1
    if e % 2 == 0 or n % 8 == 1 or n % 8 == 7:
        s = 1
    else:
        s = -1
    if a1 == 1:
        return s
    if n % 4 == 3 and a1 % 4 == 3:
        s = -s
    return s * jacobi(n % a1, a1)

